SELECT account_name 
FROM account_types 
WHERE minimum_opening_balance > 1000;

SELECT product_name
FROM account_products
WHERE product_status = 'Active';

SELECT a.account_id, a.balance, ip.payment_amount
FROM accounts a
INNER JOIN interest_payments ip ON a.account_id = ip.account_id;

SELECT payment_frequency, effective_start_date
FROM interest_payment_schedules
WHERE payment_frequency = 'Monthly' AND effective_start_date = '2022-01-01';

SELECT a.account_id, a.customer_id, a.balance, a.opened_date, u.role_name, u.permissions
FROM accounts AS a, user_roles AS u
WHERE a.account_status = 'Active' AND u.role_name = 'Admin';

SELECT account_number, account_status
FROM accounts
WHERE balance > (SELECT AVG(balance) FROM accounts);

SELECT product_name, product_status
FROM account_products
WHERE product_id = 1;

SELECT account_type_id
FROM interest_rates
WHERE interest_rate = (SELECT MAX(interest_rate) FROM interest_rates);
